-        listener(status);
-      } catch {
-        // Ignore listener errors
-      }
-    }
-  }
-
-  private timeout(ms: number, message: string): Promise<never> {
-    return new Promise((_, reject) => {
-      setTimeout(() => reject(new Error(message)), ms);
-    });
-  }
-
-  /**
-   * Get component health by name
